const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

const courseName = body.course_name || body.courseName || "Unknown Course";
const courseId = body.course_id || body.courseId || "course_unknown";
const studentId = body.student_id || body.studentId || null;
const fusionOptions = body.fusion_options || body.fusionOptions || {};

function firstPresent(...values) {
  return values.find(value => value !== undefined && value !== null);
}

function asArray(value) {
  if (Array.isArray(value)) return value;
  if (value === undefined || value === null) return [];
  return [value];
}

const directOutputs = [
  ["course_material_agent", firstPresent(body.course_knowledge_map, body.courseKnowledgeMap, body.material_agent_output, body.materialAgentOutput, body.course_material_agent_output)],
  ["lecture_signal_agent", firstPresent(body.lecture_signal_map, body.lectureSignalMap, body.lecture_agent_output, body.lectureAgentOutput, body.lecture_signal_agent_output)],
  ["exam_pattern_agent", firstPresent(body.exam_pattern_map, body.examPatternMap, body.exam_agent_output, body.examAgentOutput, body.exam_pattern_agent_output)],
  ["student_profile_agent", firstPresent(body.student_profile_map, body.studentProfileMap, body.student_agent_output, body.studentAgentOutput, body.student_profile_agent_output)]
];

const availableAgentOutputs = [];
const seen = new Set();

for (const item of asArray(body.available_agent_outputs || body.availableAgentOutputs || body.agent_outputs || body.agentOutputs)) {
  const agentName = item.agent_name || item.agentName || item.workflow_name || item.workflowName || item.name || "unknown_agent";
  const status = item.status || (item.output ? "available" : "missing");
  availableAgentOutputs.push({
    agent_name: agentName,
    status,
    reason: item.reason || null,
    output: item.output || item.result || item.data || null
  });
  seen.add(agentName);
}

for (const [agentName, output] of directOutputs) {
  if (output !== undefined && output !== null && !seen.has(agentName)) {
    availableAgentOutputs.push({
      agent_name: agentName,
      status: "available",
      reason: null,
      output
    });
    seen.add(agentName);
  }
}

for (const agentName of ["course_material_agent", "lecture_signal_agent", "exam_pattern_agent", "student_profile_agent"]) {
  if (!seen.has(agentName)) {
    availableAgentOutputs.push({
      agent_name: agentName,
      status: "not_provided",
      reason: "No corresponding upstream agent output was provided.",
      output: null
    });
  }
}

function normalizeAgentName(name) {
  const raw = String(name || "").toLowerCase();
  if (raw.includes("course") || raw.includes("material") || raw.includes("knowledge")) return "course_material_agent";
  if (raw.includes("lecture") || raw.includes("signal")) return "lecture_signal_agent";
  if (raw.includes("exam") || raw.includes("pattern") || raw.includes("question")) return "exam_pattern_agent";
  if (raw.includes("student") || raw.includes("profile")) return "student_profile_agent";
  return raw || "unknown_agent";
}

function shortText(value, max = 300) {
  return String(value ?? "").replace(/\s+/g, " ").trim().slice(0, max);
}

function addEvidence(pool, item) {
  if (!item.topic_text && !item.evidence_text && !item.summary) return;
  const sourceAgent = normalizeAgentName(item.source_agent);
  const index = pool.filter(e => e.source_agent === sourceAgent).length + 1;
  pool.push({
    evidence_id: item.evidence_id || (sourceAgent.replace(/_agent$/, "").replace(/_/g, "") + "_" + String(index).padStart(3, "0")),
    source_agent: sourceAgent,
    evidence_type: item.evidence_type || "other",
    topic_text: shortText(item.topic_text || item.topic_or_concept || item.concept_name || item.knowledge_point || item.summary, 120),
    strength: item.strength || item.signal_strength || item.frequency_level || item.severity || item.material_coverage || "unknown",
    confidence: item.confidence ?? null,
    source_refs: item.source_refs || [],
    evidence_text: shortText(item.evidence_text || item.summary || item.reasoning || item.description || item.notes, 500),
    raw: item.raw || null
  });
}

function sourceRefsFromEvidence(list) {
  return asArray(list).map(e => ({
    source_id: e.source_id || null,
    file_name: e.file_name || null,
    location: e.location || e.page || e.exam_year || e.lecture_title || null,
    evidence_text: shortText(e.evidence_text, 220)
  }));
}

function collectCourseMaterial(output, pool) {
  for (const chapter of asArray(output.knowledge_map)) {
    for (const topic of asArray(chapter.topics)) {
      for (const concept of asArray(topic.concepts)) {
        addEvidence(pool, {
          source_agent: "course_material_agent",
          evidence_type: "course_concept",
          topic_text: concept.concept_name || topic.topic_name || chapter.chapter,
          strength: concept.material_coverage || "unknown",
          confidence: concept.confidence ?? null,
          source_refs: sourceRefsFromEvidence(concept.source_evidence),
          evidence_text: concept.summary || concept.concept_type,
          raw: {
            concept_id: concept.concept_id || null,
            chapter: chapter.chapter || null,
            topic: topic.topic_name || null,
            related_concepts: concept.related_concepts || []
          }
        });
      }
    }
  }
  for (const rel of asArray(output.dependency_relations)) {
    addEvidence(pool, {
      source_agent: "course_material_agent",
      evidence_type: "dependency_relation",
      topic_text: String(rel.from || "") + " -> " + String(rel.to || ""),
      strength: "medium",
      evidence_text: rel.relation || "dependency relation",
      raw: rel
    });
  }
}

function collectLectureSignals(output, pool) {
  for (const signal of asArray(output.lecture_signals)) {
    addEvidence(pool, {
      source_agent: "lecture_signal_agent",
      evidence_type: signal.signal_type || "lecture_signal",
      topic_text: signal.topic_or_concept,
      strength: signal.signal_strength || "unknown",
      confidence: signal.confidence ?? null,
      source_refs: sourceRefsFromEvidence(signal.source_evidence),
      evidence_text: signal.summary || signal.reasoning,
      raw: { signal_id: signal.signal_id || null }
    });
  }
}

function collectExamPatterns(output, pool) {
  for (const pattern of asArray(output.pattern_summary)) {
    addEvidence(pool, {
      source_agent: "exam_pattern_agent",
      evidence_type: "exam_pattern",
      topic_text: pattern.knowledge_point,
      strength: pattern.frequency_level || "unknown",
      confidence: pattern.confidence ?? null,
      source_refs: sourceRefsFromEvidence(pattern.source_evidence),
      evidence_text: pattern.summary,
      raw: {
        pattern_id: pattern.pattern_id || null,
        question_types: pattern.question_types || [],
        ability_requirements: pattern.ability_requirements || [],
        supporting_questions: pattern.supporting_questions || []
      }
    });
  }
  for (const question of asArray(output.question_analysis)) {
    addEvidence(pool, {
      source_agent: "exam_pattern_agent",
      evidence_type: "question_analysis",
      topic_text: asArray(question.knowledge_points).join(", "),
      strength: question.difficulty_estimate || "unknown",
      source_refs: [{
        source_id: question.source_id || null,
        file_name: question.file_name || null,
        location: question.exam_year || null,
        evidence_text: shortText(question.evidence_text, 220)
      }],
      evidence_text: question.reasoning || question.evidence_text,
      raw: {
        question_id: question.question_id || null,
        detected_question_type: question.detected_question_type || null,
        ability_requirements: question.ability_requirements || []
      }
    });
  }
}

function collectStudentProfile(output, pool) {
  for (const weakness of asArray(output.weaknesses)) {
    addEvidence(pool, {
      source_agent: "student_profile_agent",
      evidence_type: "student_weakness",
      topic_text: weakness.topic_or_concept,
      strength: weakness.severity || "unknown",
      confidence: weakness.confidence ?? null,
      source_refs: sourceRefsFromEvidence(weakness.evidence),
      evidence_text: weakness.likely_reason || asArray(weakness.evidence).map(e => e.evidence_text).join(" "),
      raw: {
        weakness_id: weakness.weakness_id || null,
        weakness_type: weakness.weakness_type || null
      }
    });
  }
  for (const pattern of asArray(output.mistake_patterns)) {
    addEvidence(pool, {
      source_agent: "student_profile_agent",
      evidence_type: "mistake_pattern",
      topic_text: pattern.topic_or_concept,
      strength: "medium",
      source_refs: sourceRefsFromEvidence(pattern.evidence),
      evidence_text: pattern.summary,
      raw: {
        pattern_id: pattern.pattern_id || null,
        mistake_type: pattern.mistake_type || null,
        related_questions: pattern.related_questions || []
      }
    });
  }
  for (const item of asArray(output.knowledge_self_assessment)) {
    addEvidence(pool, {
      source_agent: "student_profile_agent",
      evidence_type: "student_self_assessment",
      topic_text: item.topic_or_concept,
      strength: item.self_assessed_level || "unknown",
      confidence: item.confidence ?? null,
      source_refs: sourceRefsFromEvidence(item.evidence),
      evidence_text: item.notes || asArray(item.evidence).map(e => e.evidence_text).join(" "),
      raw: { self_assessed_level: item.self_assessed_level || null }
    });
  }
  for (const risk of asArray(output.risk_flags)) {
    addEvidence(pool, {
      source_agent: "student_profile_agent",
      evidence_type: "student_risk",
      topic_text: risk.risk_type,
      strength: risk.severity || "unknown",
      source_refs: sourceRefsFromEvidence(risk.evidence),
      evidence_text: risk.description,
      raw: risk
    });
  }
}

const evidencePool = [];
const normalizedOutputs = [];

for (const entry of availableAgentOutputs) {
  const agentName = normalizeAgentName(entry.agent_name);
  const output = entry.output || {};
  const isAvailable = entry.status === "available" && output && typeof output === "object";
  normalizedOutputs.push({
    agent_name: agentName,
    status: entry.status,
    reason: entry.reason || null,
    has_output: isAvailable,
    workflow_name: output.workflow_name || null
  });

  if (!isAvailable) continue;
  if (agentName === "course_material_agent") collectCourseMaterial(output, evidencePool);
  else if (agentName === "lecture_signal_agent") collectLectureSignals(output, evidencePool);
  else if (agentName === "exam_pattern_agent") collectExamPatterns(output, evidencePool);
  else if (agentName === "student_profile_agent") collectStudentProfile(output, evidencePool);
  else {
    addEvidence(evidencePool, {
      source_agent: agentName,
      evidence_type: "agent_output_summary",
      topic_text: output.workflow_name || agentName,
      strength: "unknown",
      evidence_text: JSON.stringify(output).slice(0, 500)
    });
  }
}

const availableSources = normalizedOutputs.filter(x => x.has_output).map(x => x.agent_name);
const missingSources = normalizedOutputs.filter(x => !x.has_output).map(x => ({
  agent_name: x.agent_name,
  status: x.status,
  reason: x.reason || "No usable output."
}));

const evidenceCoverage = {
  available_sources: [...new Set(availableSources)],
  missing_sources: missingSources,
  evidence_count: evidencePool.length,
  coverage_level: availableSources.length >= 4 ? "complete" : availableSources.length >= 2 ? "partial" : availableSources.length === 1 ? "minimal" : "none"
};

return [{
  json: {
    workflow_name: "evidence_fusion_agent",
    course_id: courseId,
    course_name: courseName,
    student_id: studentId,
    fusion_options: {
      max_focus_candidates: fusionOptions.max_focus_candidates || fusionOptions.maxFocusCandidates || 10,
      allow_low_evidence_candidates: fusionOptions.allow_low_evidence_candidates ?? fusionOptions.allowLowEvidenceCandidates ?? true
    },
    normalized_agent_outputs: normalizedOutputs,
    evidence_coverage: evidenceCoverage,
    evidence_pool: evidencePool,
    original_input_summary: {
      available_agent_output_entries: availableAgentOutputs.length,
      direct_input_keys: Object.keys(body)
    },
    constraints: {
      no_exam_prediction: true,
      no_must_test_language: true,
      do_not_assume_all_sources_available: true,
      every_priority_requires_evidence_chain: true,
      missing_sources_must_lower_confidence_or_add_caveats: true
    }
  }
}];

const previous = $("Build Concept Alignment Prompt").first().json;
const llmResult = $input.first().json;
function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  const fence = String.fromCharCode(96).repeat(3);
  return text
    .replace(new RegExp("^" + fence + "(?:json)?\\s*", "i"), "")
    .replace(new RegExp("\\s*" + fence + "$", "i"), "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") raw = JSON.stringify(raw);
  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);
  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) return JSON.parse(text.slice(start, end + 1));
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  parsed = {
    workflow_name: "concept_alignment_expert",
    parser_error: true,
    error_message: error.message,
    concept_clusters: [],
    alignment_uncertainties: ["Could not parse Concept Alignment output."]
  };
}

return [{ json: { ...previous, expert_role: "concept_alignment_result", concept_alignment_result: parsed } }];

const items = $input.all().map(item => item.json);
const base = items.find(item => Array.isArray(item.evidence_pool)) || items[0] || {};
const conceptResult = items.find(item => item.concept_alignment_result)?.concept_alignment_result || { concept_clusters: [], alignment_uncertainties: [] };
const relevanceResult = items.find(item => item.relevance_mapping_result)?.relevance_mapping_result || { source_links: [], relevance_uncertainties: [] };
const missingResult = items.find(item => item.missing_evidence_result)?.missing_evidence_result || { missing_evidence_impacts: [], coverage_notes: [] };

const evidenceById = Object.fromEntries((base.evidence_pool || []).map(e => [e.evidence_id, e]));
function evidenceFor(ids) { return (ids || []).map(id => evidenceById[id]).filter(Boolean); }

const fusionBoard = (conceptResult.concept_clusters || []).map(cluster => {
  const linkedEvidence = evidenceFor(cluster.linked_evidence_ids);
  const sourceLinks = (relevanceResult.source_links || []).filter(link => {
    const ids = link.supporting_evidence_ids || [];
    return ids.some(id => (cluster.linked_evidence_ids || []).includes(id)) || (link.topic_or_concept && String(cluster.canonical_concept || "").toLowerCase().includes(String(link.topic_or_concept).toLowerCase()));
  });
  return {
    cluster_id: cluster.cluster_id,
    canonical_concept: cluster.canonical_concept,
    aliases: cluster.aliases || [],
    source_agents: [...new Set(linkedEvidence.map(e => e.source_agent))],
    linked_evidence: linkedEvidence,
    source_links: sourceLinks,
    alignment_confidence: cluster.alignment_confidence ?? null,
    notes: cluster.notes || null
  };
});

const clusteredIds = new Set((conceptResult.concept_clusters || []).flatMap(cluster => cluster.linked_evidence_ids || []));
const unmappedEvidence = (base.evidence_pool || []).filter(e => !clusteredIds.has(e.evidence_id));

const mappingResult = {
  workflow_name: "adaptive_parallel_mapping_board",
  concept_clusters: conceptResult.concept_clusters || [],
  source_links: relevanceResult.source_links || [],
  missing_evidence_impacts: missingResult.missing_evidence_impacts || [],
  mapping_uncertainties: [
    ...(conceptResult.alignment_uncertainties || []),
    ...(relevanceResult.relevance_uncertainties || []),
    ...(missingResult.coverage_notes || [])
  ]
};

return [{
  json: {
    ...base,
    concept_alignment_result: conceptResult,
    relevance_mapping_result: relevanceResult,
    missing_evidence_result: missingResult,
    mapping_result: mappingResult,
    fusion_board: fusionBoard,
    unmapped_evidence: unmappedEvidence,
    parallel_expert_meta: {
      expert_count: 3,
      experts: ["concept_alignment", "relevance_mapping", "missing_evidence"],
      merged_at: new Date().toISOString()
    }
  }
}];

