  return text
    .replace(new RegExp("^" + fence + "(?:json)?\\s*", "i"), "")
    .replace(new RegExp("\\s*" + fence + "$", "i"), "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") {
    raw = JSON.stringify(raw);
  }

  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);

  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) {
      const candidate = text.slice(start, end + 1);
      return JSON.parse(candidate);
    }
    throw firstError;
  }
}


let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  parsed = {
    workflow_name: "evidence_fusion_agent",
    parser_error: true,
    error_message: error.message,
    evidence_coverage: previous.evidence_coverage,
    fusion_summary: {
      total_focus_candidates: 0,
      high_priority_count: 0,
      main_drivers: ["parser_error"],
      global_uncertainty_level: "high"
    },
    review_focus_candidates: [],
    conflicts_or_gaps: [],
    uncertainties: ["Could not parse Priority Synthesizer output."]
  };
}

parsed.workflow_name = parsed.workflow_name || "evidence_fusion_agent";
parsed.evidence_coverage = parsed.evidence_coverage || previous.evidence_coverage;
parsed.fusion_summary = parsed.fusion_summary || {};
parsed.review_focus_candidates = Array.isArray(parsed.review_focus_candidates) ? parsed.review_focus_candidates : [];
parsed.conflicts_or_gaps = Array.isArray(parsed.conflicts_or_gaps) ? parsed.conflicts_or_gaps : [];
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];

return [{ json: { ...previous, draft_fusion_output: parsed } }];

