    overall_risk_level: "high",
    overreach_flags: [{
      candidate_id: "global",
      risk_type: "critic_parser_error",
      severity: "high",
      description: "Could not parse critic output: " + error.message,
      repair_instruction: "Finalize conservatively and add parser uncertainty."
    }],
    required_repairs: ["Add uncertainty because critic output could not be parsed."],
    safe_to_finalize: false
  };
}

parsed.workflow_name = parsed.workflow_name || "evidence_fusion_critic";
parsed.overreach_flags = Array.isArray(parsed.overreach_flags) ? parsed.overreach_flags : [];
parsed.required_repairs = Array.isArray(parsed.required_repairs) ? parsed.required_repairs : [];
parsed.safe_to_finalize = parsed.safe_to_finalize === true && parsed.passed === true;

return [{ json: { ...previous, critic_report: parsed } }];

