      critic_passed: previous.critic_report.safe_to_finalize === true,
      overall_risk_level: previous.critic_report.overall_risk_level || "high",
      repairs_applied: ["Final repair output could not be parsed; returning conservative draft with parser uncertainty."]
    },
    uncertainties: [
      ...(previous.draft_fusion_output.uncertainties || []),
      "Final repair output could not be parsed."
    ]
  };
}

parsed.workflow_name = "evidence_fusion_agent";
parsed.course_id = parsed.course_id || previous.course_id;
parsed.course_name = parsed.course_name || previous.course_name;
parsed.student_id = parsed.student_id ?? previous.student_id;
parsed.evidence_coverage = parsed.evidence_coverage || previous.evidence_coverage;
parsed.fusion_summary = parsed.fusion_summary || {};
parsed.review_focus_candidates = Array.isArray(parsed.review_focus_candidates) ? parsed.review_focus_candidates : [];
parsed.conflicts_or_gaps = Array.isArray(parsed.conflicts_or_gaps) ? parsed.conflicts_or_gaps : [];
